prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?endCount WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "4e8df28e6d9f4afe970d06522542e830" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  {
    SELECT (COUNT(DISTINCT ?end) AS ?endCount) WHERE {
      ?end a bboExt:EndEvent ;
           tai:belongsTo ?choreo .
    }
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?choreo (COUNT(DISTINCT ?end) AS ?endCount) WHERE {
  VALUES ?mid { "4e8df28e6d9f4afe970d06522542e830" }

  ?model a bboExt:Model ;
         bbo:name ?modelName .
  {
    ?model tai:normalizedId ?mid .
  }
  UNION
  {
    ?model tai:originalId ?mid .
  }

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?end a bboExt:EndEvent ;
       tai:belongsTo ?choreo .
}
GROUP BY ?model ?modelName ?choreo
ORDER BY DESC(?endCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?start ?startName ?endReachableCount WHERE {
  VALUES ?mid { "4e8df28e6d9f4afe970d06522542e830" }

  ?model a bboExt:Model .
  {
    ?model tai:normalizedId ?mid .
  }
  UNION
  {
    ?model tai:originalId ?mid .
  }
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  {
    SELECT ?start (COUNT(DISTINCT ?end) AS ?endReachableCount) WHERE {
      ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?end .
      ?end a bboExt:EndEvent ;
           tai:belongsTo ?choreo .
    } GROUP BY ?start
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
ASK {
  VALUES ?mid { "4e8df28e6d9f4afe970d06522542e830" }

  ?model a bboExt:Model .
  { ?model tai:normalizedId ?mid } UNION { ?model tai:originalId ?mid }

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .

  # Find a reachable node that cannot reach any EndEvent
  ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?n .
  {
    SELECT (COUNT(DISTINCT ?e) AS ?endsFromN) WHERE {
      ?n ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?e .
      ?e a bboExt:EndEvent ;
         tai:belongsTo ?choreo .
    }
  }
}
